item.description:
 &lt;h3 id=&#34;mysql学习章节&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mysql学习章节&#34;&gt;#&lt;/a&gt; &lt;em&gt;&lt;strong&gt;MySQL学习章节&lt;/strong&gt;&lt;/em&gt;&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;MySQL数据库&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;启动与停止&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;启动：&lt;code&gt;net start mysql80&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;停止：&lt;code&gt;net start mysql80&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;客户端连接&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;方式一：mysql提供的客户端命令行工具&lt;/p&gt;
&lt;p&gt;方式二：Windows系统提供的命令行：&lt;code&gt;mysql -u root -p&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;数据模型&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;关系型数据库：通过表结构存储数据&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;sql&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#sql&#34;&gt;#&lt;/a&gt; SQL&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;sql的通用语法&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;sql语句可以单行或是多行书写，以分号结尾&lt;/li&gt;
&lt;li&gt;sql语句可以使用空格缩进来增强语句的可读性&lt;/li&gt;
&lt;li&gt;MySQL数据库的 sql 语句不区分大小写，关键字建议使用大写&lt;/li&gt;
&lt;li&gt;注释：
&lt;ul&gt;
&lt;li&gt;单行注释：--或是#注释内容&lt;/li&gt;
&lt;li&gt;对行注释：/* 注释内容*/&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;sql语句的分类&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;DDL：数据定义语言，用来定义数据库对象（数据库，表，字段）&lt;/li&gt;
&lt;li&gt;DML：数据操作语言，用于对数据库表中的数据进行增删改&lt;/li&gt;
&lt;li&gt;DQL：数据查询语言，用于查询数据库中表的记录&lt;/li&gt;
&lt;li&gt;DCL：数据控制语言，用来创建数据库用户控制数据库的访问权限&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;ddl语句&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ddl语句&#34;&gt;#&lt;/a&gt; &lt;strong&gt;DDL语句&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;数据库操作&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;查询所有数据库：&lt;code&gt;SHOW DATABASES;&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;查询当前数据库：&lt;code&gt;SELECT DATEBASE();&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;创建：&lt;code&gt;CREATE [IF NOT EXISTS]数据库名[DEFAULT CHARSET字符集] [COLLATE 排序规则]&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;删除：&lt;code&gt;drop database[if exists]数据库名&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;使用：&lt;code&gt;use 数据库名&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数据库操作——表结构查询&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;查询当前数据库所有表：&lt;code&gt;show tables&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;查询表结构：&lt;code&gt;desc 表名&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;查询指定表的建表语句：&lt;code&gt;show create table表名&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数据库操作——表结构的创建&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;pre class=&#34;shiki shiki-themes vitesse-light vitesse-dark&#34; style=&#34;background-color:#ffffff;--shiki-dark-bg:#121212;color:#393a34;--shiki-dark:#dbd7caee&#34; tabindex=&#34;0&#34;&gt;&lt;code class=&#34;language-text&#34;&gt;&lt;span class=&#34;line&#34;&gt;&lt;span&gt;create table 表名（&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;line&#34;&gt;&lt;span&gt;	字段一 字段一类型[comment 字段一注释],&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;line&#34;&gt;&lt;span&gt;	字段二 字段二类型[comment 字段二注释],&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;line&#34;&gt;&lt;span&gt;	......&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;line&#34;&gt;&lt;span&gt;	字段n 字段n类型[comment 字段n注释]&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;line&#34;&gt;&lt;span&gt;)[comment 表注释];&lt;/span&gt;&lt;/span&gt;&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数据库操作——数据类型&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;varchar&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数据库操作——修改&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;添加字段：&lt;code&gt;alter table 表名add 字段名 类型（长度）[comment 注释][约束]；&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;修改字段名和字段类型：&lt;code&gt;alter table 表名 change 旧字段名 新字段名 类型（长度）[comment 注释][约束]；&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;删除字段：&lt;code&gt;alter table 表名 drop 字段名&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;修改表名：&lt;code&gt;alter table 表名 rename to新表名&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数据库操作——删除&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;删除表：&lt;code&gt;drop table 表名&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;删除指定表，并重新创建表（一张全新的表）：&lt;code&gt;truncate table 表名&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;mysql-的图形化界面&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mysql-的图形化界面&#34;&gt;#&lt;/a&gt; Mysql 的图形化界面&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;学习使用datagrip&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;dml语句&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dml语句&#34;&gt;#&lt;/a&gt; DML语句&lt;/h3&gt;
&lt;p&gt;对数据库中的表进行增删改操作&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;添加数据（insert）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;修改数据（update)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;删除数据（delete)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;DML——添加数据&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;给指定字段添加数据：&lt;code&gt;insert into 表名（字段名1，字段名2，...）values(值1，值2...);&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;给全部字段添加数据：&lt;code&gt;insert into 表名 values（值1，值2，...);&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;批量添加数据:&lt;/p&gt;
&lt;p&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;insert into 表名（字段名1，字段名2，...) values(值1，值2，...),(值1，值2，...);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;`insert into 表名values(值1，值2，...),(值1，值2，...);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;DML——修改数据&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;update 表名 set 字段名=值1，字段名=值2，...[where条件];&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;DML——删除数据&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;delete from 表名[where 条件]&lt;/code&gt;delete不能删除某一个字段的值（可以使用update)&lt;/li&gt;
&lt;li&gt;where条件可以有，也可以没有，如果没有条件，会删除整张表的所有数据&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;

 &lt;h3 id=&#34;计算机主要由硬件和软件组成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计算机主要由硬件和软件组成&#34;&gt;#&lt;/a&gt; 计算机主要由硬件和软件组成&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;虚拟机就是一个虚拟的电脑；模拟出了一个虚拟的硬件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;安装Centos:遇到的困难：阿里云的链接无法使用&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;解决方法：通过清华大学镜像网站下载完成&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;远程连接Linux:&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;一、掌握图形化与命令行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;图形化：通过资源管理器&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;通过cmd命令行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;使用Linux 基本使用命令行，效率高并且稳定&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;工具的使用&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;window实现交互不方便，因此借助第三方平台进行操作&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;第三方软件：FinallShell&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;学习如何通过Finalshell远程连接Linux&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;遇到问题：输入获取物理主机IP地址时，在终端输入ifconfig时ens33后并没有IP地址&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;解决方案：询问豆包&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;问题根源：没有启动VMware NAT Service 以及VMware DHCP Service ，导致虚拟机没有被分配IP&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;em&gt;&lt;strong&gt;注意：Linux系统重启之后IP地址可能会变化，如果变化，就重新手动匹配IP&lt;/strong&gt;&lt;/em&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;配置好之后就可以通过FinalShell远程连接linux&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;虚拟机快照在损坏操作系统的情况&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#虚拟机快照在损坏操作系统的情况&#34;&gt;#&lt;/a&gt; 虚拟机快照：（在损坏操作系统的情况）&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;作用：通过快照将当前虚拟机的状态保存下来，吗，，，，，，以后可以通过快照恢复虚拟机到保存的状态&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;步骤:&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;首先，需要关机虚拟机，右键点击选择快照&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;然后，点击拍摄快照&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;当虚拟机出现问题之后，点击快照，点击“转到”按钮，&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;linux基础命令结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#linux基础命令结构&#34;&gt;#&lt;/a&gt; Linux基础命令结构&lt;/h3&gt;
&lt;p&gt;Linux中的目录结构：&lt;/p&gt;
&lt;p&gt;路径描述：在Linux系统中“ / ”,且只有一个顶级目录，即为根目录。&lt;/p&gt;
&lt;p&gt;但是在windows系统中“ \ &amp;quot;,有多个顶级目录，即为各个盘符&lt;/p&gt;
&lt;h3 id=&#34;linux操作系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#linux操作系统&#34;&gt;#&lt;/a&gt; Linux操作系统&lt;/h3&gt;
&lt;p&gt;Linux命令行：&lt;code&gt;command [-option(可选，非必填)] [parameter（可选，非必填]&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;eg&lt;/code&gt;.   &lt;code&gt;ls -l /home/pipixia &lt;/code&gt;  ls是命令本身，-l是选项，&lt;code&gt;/home/pipixia&lt;/code&gt;是参数：以列表的形式显示/home/&lt;code&gt;pipixia&lt;/code&gt;的内容&lt;/p&gt;
&lt;h3 id=&#34;ls&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ls&#34;&gt;#&lt;/a&gt; ls&lt;/h3&gt;
&lt;p&gt;作用：展示当前的工作目录（以平铺的形式）（一般默认是Home）&lt;/p&gt;
&lt;p&gt;ls命令的参数（-a , -l ,-h)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;-a: 表示all的意思，即列出全部的文件，包含以’ . &#39;开头的隐藏文件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;-l: 表示以列表的形式展现内容&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;-h：表示以容易阅读的形式用单位展示（K,B.L)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;命令参数的组合使用：同时使用多个参数的效果&lt;code&gt;eg&lt;/code&gt; . &lt;code&gt;ls -a -l&lt;/code&gt;   &lt;code&gt;ls -al&lt;/code&gt;   &lt;code&gt;ls -la&lt;/code&gt;   &lt;code&gt;ls -lah&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;cd&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cd&#34;&gt;#&lt;/a&gt; &lt;code&gt;cd&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;作用：更改当前所在的工作目录（默认home目录）&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;cd ~&lt;/code&gt;和&lt;code&gt;cd&lt;/code&gt;默认都是回到 家目录下，但是管理员和普通用户的家目录不同&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;pwd&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#pwd&#34;&gt;#&lt;/a&gt; pwd&lt;/h3&gt;
&lt;p&gt;作用：通过pwd命令来查看当前所在的工作目录  无需参数&lt;/p&gt;
&lt;h3 id=&#34;相对路径-绝对路径-特殊路径&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#相对路径-绝对路径-特殊路径&#34;&gt;#&lt;/a&gt; 相对路径、绝对路径、特殊路径&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;1.相对路径：以当前路径为起点，路径无需以/开头&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;2.绝对路径：以根目录为起点，路径描述以/开头（不方便）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;3.特殊路径：（1） &amp;quot;&lt;code&gt;cd.&lt;/code&gt;&amp;quot; :表示当前目录&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;​                       （2） “&lt;code&gt;cd ..&lt;/code&gt;&amp;quot;:表示切换到上一级目录（&amp;quot;&lt;code&gt;cd ../..&lt;/code&gt;&amp;quot;表示切换到上二级目录）&lt;/p&gt;
&lt;p&gt;​                        （3） ”&lt;code&gt;cd~&lt;/code&gt;&amp;quot;：表示切换到HOME目录&lt;/p&gt;
&lt;h3 id=&#34;mkdir&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mkdir&#34;&gt;#&lt;/a&gt; mkdir&lt;/h3&gt;
&lt;p&gt;作用：创建新的目录：参数必填，（-p参数可选  例：&lt;code&gt;mkdir -p itcast/good/666&lt;/code&gt;,可以通过-p参数将一整条参数都创建完成）&lt;/p&gt;
&lt;p&gt;注意:因为创建文件的权限比较大，所以用&lt;code&gt;mkdir&lt;/code&gt;创建目录时需要在HOME目录下&lt;/p&gt;
&lt;h3 id=&#34;文件操作命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#文件操作命令&#34;&gt;#&lt;/a&gt; 文件操作命令&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;touch: 创建文件，touch 命令无选项，参数必填，表示要创建的文件路径，相对、绝对、特殊路径符均可使用&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;cat: 查看文件的内容（必填参数）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;more: 查看文件内容，但与cat的区别在于more支持翻页，如果文件内容过多，可以一页页地展示(必填参数)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;cp: 可以用于复制文件和文件夹   语法：&lt;code&gt; cp&lt;/code&gt; [-r] 参数1  参数2（-r，可选，用于复制文件夹时使用，表示递归，参数1表示被复制的文件和文件夹，参数2，表示要被复制去的地方）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;mv: 移动文件和文件夹，并拥有改名的效果   语法： mv  参数1  参数2&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;rm: 用于文件和文件夹的删除    语法：  rm  [-r -f] 参数1  参数2  .......参数N(-r 用于删除文件夹，-f表示force,强制删除，一般用户用不到-f)可以一次性删除多个目标。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;rm的通配符&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rm的通配符&#34;&gt;#&lt;/a&gt; rm的通配符&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;符号“*”表示通配符，即匹配任意内容，可以用来做模糊匹配&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;test*表示匹配任意以test开头的内容&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;*test表示匹配任意以test结尾的内容&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;*test *表示匹配任意包含test的内容&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;提权：&lt;code&gt;sudo su &lt;/code&gt;和&lt;code&gt;su -root-&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;输入exit返回普通用户&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;which-and-find&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#which-and-find&#34;&gt;#&lt;/a&gt; which  and find&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;which命令: 语法：&lt;code&gt;which  文件的路径&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;find命令：（1）按文件名查找   语法：find 起始路径  -name &amp;quot;被查找的文件名&amp;quot;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;​                       查找文件的通配符“*”&lt;/p&gt;
&lt;p&gt;​                          （2）按文件大小查找文件  语法： find  起始路径  -size +|-n[&lt;code&gt;KMG&lt;/code&gt;]       +、—分别表示大于和小于n表示大小数字  ，KMG表示大小单位&lt;/p&gt;
&lt;p&gt;​                        例：  找大于&lt;code&gt;1GB&lt;/code&gt;的文件：find / -size +1&lt;code&gt;G&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;grep命令和wc命令和管道符&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#grep命令和wc命令和管道符&#34;&gt;#&lt;/a&gt; grep命令和wc命令和管道符&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;grep命令&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;作用：通过grep命令，从文件中通过关键字过滤文件行  语法：  &lt;code&gt;grep  [-n] 关键字 文件路径&lt;/code&gt;{&lt;strong&gt;-n&lt;/strong&gt;,可选，表示在结果中显示匹配的行的行号}(&lt;strong&gt;关键字&lt;/strong&gt;，必填，表示过滤的关键字，带有空格和其他特殊符号，建议使用““将关键字包围起来)（&lt;strong&gt;文件路径&lt;/strong&gt;，可作为内容输入端口）&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;wc命令&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;作用：做数量统计，统计文件的行数，单词数目等&lt;/li&gt;
&lt;li&gt;语法： &lt;code&gt;wc [-c -m -l -w]文件路径&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;-c: 统计byte数量&lt;/li&gt;
&lt;li&gt;-m: 统计字符数量&lt;/li&gt;
&lt;li&gt;-l: 统计行数&lt;/li&gt;
&lt;li&gt;-w：统计单词数量&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;管道符“|”&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;含义：将管道符组左边命令的结果作为右边命令的输入&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;可以用于和其他的命令连用&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;管道符的基础应用&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;echo-反引号-tail命令-重定向符的使用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#echo-反引号-tail命令-重定向符的使用&#34;&gt;#&lt;/a&gt; echo、 反引号`、tail命令、重定向符的使用&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;echo&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在命令行中输出指定内容&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;反引号“`&amp;quot;&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;··包围的内容将会被作为命令去执行，而不是作为字符被输出&lt;/li&gt;
&lt;li&gt;例： &lt;strong&gt;etho &lt;code&gt;pwd&lt;/code&gt;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;重定向符&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;**&amp;quot;&amp;gt;&amp;quot;**将左侧命令的结果，&lt;strong&gt;覆盖&lt;/strong&gt;写入到符号右边的指定的文件中&lt;/li&gt;
&lt;li&gt;**“&amp;gt;&amp;gt;&amp;quot;**将左侧命令的结果，&lt;strong&gt;追加&lt;/strong&gt;写入到符号右侧指定文件中&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;tail命令&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;作用：可以查看文件尾部内容（默认查看10行）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语法：&lt;code&gt;tail [-f  - num] Linux路径&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;vi编辑器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vi编辑器&#34;&gt;#&lt;/a&gt; vi编辑器&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;语法&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;vi  文件路径&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;vim  文件路径&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;vi/vim命令模式的快捷键&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;i&lt;/strong&gt;: 在当前光标位置进入输入模式&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;a&lt;/strong&gt;: 在当前光标位置之后进入输入模式&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;。。。。。。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;linux用户和权限&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#linux用户和权限&#34;&gt;#&lt;/a&gt; Linux用户和权限&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;su 和exit命令&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;su语法&lt;/strong&gt;： &lt;code&gt;su [-] [用户名]&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;exit&lt;/strong&gt;： 退出超级管理员&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;用户、用户组&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;用户组管理&lt;/strong&gt;（需要用root权限才能创建）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;创建用户组：&lt;code&gt;groupadd 用户组名&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;删除用户组：&lt;code&gt;groupdel 用户组名&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;用户管理&lt;/strong&gt;：1.创建用户：&lt;code&gt;useradd [-g  -d]用户名&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;-g: 指定用户的组，不指定-g,会创建同名组并自动加入，指定-g需要组已经存在&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;-d: 指定用户HOME目录，不指定，HOME目录默认在：  &lt;code&gt;/home/用户名&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;退出当前用户：logout&lt;/p&gt;
&lt;p&gt;2.删除用户：&lt;code&gt;userdel [-r] 用户名&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;​     &lt;strong&gt;-r&lt;/strong&gt;: 删除用户的home目录，若不使用-r时，删除用户时，HOME目录保存&lt;/p&gt;
&lt;p&gt;3.&lt;strong&gt;&lt;code&gt;id&lt;/code&gt;命令&lt;/strong&gt;：查看用户所属组&lt;/p&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;usermod -aG 用户组，用户名&lt;/code&gt;&lt;/strong&gt;:将指定的用户加入到指定的用户组&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;getent命令&lt;/strong&gt;：&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;​    语法:&lt;code&gt;getent passwd&lt;/code&gt;可以查看当前系统有哪些用户&lt;/p&gt;
&lt;p&gt;​    语法：&lt;code&gt;getent group&lt;/code&gt;可以查看当前系统内有哪些用户组&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;查看linux中的权限&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#查看linux中的权限&#34;&gt;#&lt;/a&gt; 查看Linux中的权限&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;所属用户权限&lt;/th&gt;
&lt;th&gt;所属用户组权限&lt;/th&gt;
&lt;th&gt;其他用户权限&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;r w x -&lt;/td&gt;
&lt;td&gt;r w x  -&lt;/td&gt;
&lt;td&gt;r w x  -&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;rwx的含义&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;r: 表示读的权限（4）&lt;/li&gt;
&lt;li&gt;w: 表示写的权限（2）&lt;/li&gt;
&lt;li&gt;x：表示执行的权限（1）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;使用chmod命令修改文件文件夹的权限信息&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#使用chmod命令修改文件文件夹的权限信息&#34;&gt;#&lt;/a&gt; 使用&lt;code&gt;chmod&lt;/code&gt;命令，修改文件，文件夹的权限信息&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;语法：&lt;code&gt;chmod [-R] 权限 文件或文件夹&lt;/code&gt;   &lt;strong&gt;-R&lt;/strong&gt;: 对文件或文件夹内的全部内容做同样的操作&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;使用chown命令修改文件文件夹的所属用户和用户组-只能适用于root用户执行&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#使用chown命令修改文件文件夹的所属用户和用户组-只能适用于root用户执行&#34;&gt;#&lt;/a&gt; 使用&lt;code&gt;chown&lt;/code&gt;命令，修改文件，文件夹的所属用户和用户组  &lt;em&gt;只能适用于root用户执行&lt;/em&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;语法： &lt;code&gt;chown [-R] [用户][:] [用户组] 文件或文件夹&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;linux的实用操作&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#linux的实用操作&#34;&gt;#&lt;/a&gt; Linux的实用操作&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;1. 强制停止的快捷键&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;语法：&lt;code&gt;ctrl+c&lt;/code&gt;强制停止&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;2.强制退出登出的快捷键&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;语法：&lt;code&gt;ctrl+d&lt;/code&gt;强制退出账户（与exit以及logout的作用相似）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;3.历史搜索命令&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;history&lt;/code&gt;    搜索过去的命令&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;!+[要搜的前缀开头]&lt;/code&gt;   例：!p 就能搜到最近一次以p开头的命令&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;ctrl+r&lt;/code&gt;    输入内容去匹配历史命令&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;4.光标移动快捷键&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;ctrl+a&lt;/code&gt;  ：跳到命令开头&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ctrl+e&lt;/code&gt;  ：跳到命令结尾&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ctrl+键盘右键&lt;/code&gt;   ：向右跳一个单词&lt;/li&gt;
&lt;li&gt;&lt;code&gt;ctrl+键盘左键&lt;/code&gt;   ： 向左跳一个单词&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;5.清屏快捷键&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;ctrl+l  或  clear&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;使用yum为centos安装软件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#使用yum为centos安装软件&#34;&gt;#&lt;/a&gt; 使用yum为CentOS安装软件&lt;/h3&gt;
&lt;p&gt;&lt;em&gt;&lt;strong&gt;使用命令行yum命令安装软件&lt;/strong&gt;&lt;/em&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;语法：&lt;code&gt;yum [-y] [install] | [remove] | [search] 软件名&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;[-y],自动确认，无需手动确认安装或卸载&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;yum 命令需要root 权限，并且需要联网&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;掌握使用systemctl命令控制软件的启动和关闭&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#掌握使用systemctl命令控制软件的启动和关闭&#34;&gt;#&lt;/a&gt; 掌握使用systemctl命令控制软件的启动和关闭&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;语法：  &lt;code&gt;systemctl start | stop | status | enable | disable 服务名&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;systemctl 控制的软件，一般称为服务&lt;/li&gt;
&lt;li&gt;enable :开机自启动&lt;/li&gt;
&lt;li&gt;status:看状态&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;使用ln命令创建链接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#使用ln命令创建链接&#34;&gt;#&lt;/a&gt; 使用ln命令创建链接&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;作用：  在系统中创建软链接，可以将文件，文件夹链接到其他位置（类似于快捷方式）&lt;/li&gt;
&lt;li&gt;语法：  &lt;code&gt;ln -s 参数1 参数2&lt;/code&gt;
&lt;ul&gt;
&lt;li&gt;-s:  创建如软链接&lt;/li&gt;
&lt;li&gt;参数1：被链接的文件和文件夹&lt;/li&gt;
&lt;li&gt;参数2：要链接去的目的地&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;日期和时区&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#日期和时区&#34;&gt;#&lt;/a&gt; 日期和时区&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;1. date命令查看日期时间&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;语法：  &lt;code&gt;date&lt;/code&gt;[-d] [+格式化字符串]&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;[-d]：按照给定的字符串显示日期，一般用于日期计算&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;格式字符串：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;[%Y]：年&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;[%y]：年份后两位数字（00..99）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;[%m]：月份（01..12）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;[%d]： 日期（01..30）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;[%H]： 小时（00..23）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;[%M]： 分钟（00..59）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;[%S]： 秒（00.60）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;[%s]： 自&lt;code&gt;1970-01-01 00:00:00 UTC&lt;/code&gt; 到现在的秒数&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;可以自定义时间展现的形式&lt;/li&gt;
&lt;li&gt;输入date本身，会出现当前时间&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;2.修改时区（需要使用root权限）&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;rm -f /etc/localtime&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;ln -s /usr/share/zoneinfo/Asia/Shanghai /etc/localtime&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;将&lt;code&gt;ntpd&lt;/code&gt;设为自启动模式，联网自动校准时间&lt;/p&gt;
&lt;p&gt;也可以&lt;code&gt;ntpdate -u ntp.aliyun.com&lt;/code&gt;  阿里云校准时间&lt;/p&gt;
&lt;h3 id=&#34;ip地址和主机名&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ip地址和主机名&#34;&gt;#&lt;/a&gt; &lt;code&gt;IP&lt;/code&gt;地址和主机名&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;查看IP：&lt;code&gt;ifconfig&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;查看主机名：&lt;code&gt;hostname&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;修改主机名：（需要root权限）&lt;code&gt;hostnamectl set -hostname 主机名&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;虚拟机配置固定ip已完成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#虚拟机配置固定ip已完成&#34;&gt;#&lt;/a&gt; 虚拟机配置固定&lt;code&gt;IP&lt;/code&gt;:已完成&lt;/h3&gt;
&lt;h3 id=&#34;ping命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ping命令&#34;&gt;#&lt;/a&gt; ping命令&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;作用：通过ping命令，检查指定的网络服务器是否是可联通状态&lt;/li&gt;
&lt;li&gt;语法：&lt;code&gt;ping [-c num] ip 或主机名&lt;/code&gt;
&lt;ul&gt;
&lt;li&gt;[-c]：检查的次数，不使用-c选项，将无限次持续检查&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;wget&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#wget&#34;&gt;#&lt;/a&gt; &lt;code&gt;wget&lt;/code&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;作用：&lt;code&gt;wget&lt;/code&gt;是非交互式文件下载器，可以在命令行中下载网络文件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语法：&lt;code&gt;wget [-b] url&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;-b: 可选，后台下载，会将日志写到当前工作目录的&lt;code&gt;wegt-log&lt;/code&gt;文件中&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;url&lt;/code&gt;:下载链接&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;curl&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#curl&#34;&gt;#&lt;/a&gt; curl&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;作用：可以发送&lt;code&gt;http&lt;/code&gt;网络请求，可用于：下载文件，获取信息&lt;/li&gt;
&lt;li&gt;语法：&lt;code&gt;curl [-0] url&lt;/code&gt;
&lt;ul&gt;
&lt;li&gt;-0,用于下载文件，当&lt;code&gt;url&lt;/code&gt;是下载链接时，可以使用此选项保存文件&lt;/li&gt;
&lt;li&gt;&lt;code&gt;url&lt;/code&gt;:要发起请求的网络地址&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;端口&lt;/strong&gt;&lt;/p&gt;
&lt;h3 id=&#34;netstat命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#netstat命令&#34;&gt;#&lt;/a&gt; &lt;code&gt;netstat&lt;/code&gt;命令&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;查看指定端口的占用情况&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语法：&lt;code&gt;netstat -anp|grep 端口号&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;进程管理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#进程管理&#34;&gt;#&lt;/a&gt; 进程管理&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;定义：每一个程序在运行时，被操作系统注册为系统中的一个进程，并会为每一个进程都分配一个独有的的：进程ID&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;查看进程的语法：&lt;code&gt;ps [-e -f]&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;-e: 显示全部的进程&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;-f: 以完全格式化的形式展现全部的信息固定用法：&lt;code&gt;ps -ef&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;与管道符公用，过滤信息，快速查找&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;关闭进程&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;强制关闭进程：&lt;code&gt;kill [-9] 进程ID&lt;/code&gt;
&lt;ul&gt;
&lt;li&gt;-9:表示强制关闭进程&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;top命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#top命令&#34;&gt;#&lt;/a&gt; top命令&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;语法：&lt;code&gt;top&lt;/code&gt;  查看CPU使用情况&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;top -i&lt;/code&gt;:  只要查看启用的&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;h键：可以用来查看快捷键&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;磁盘的信息监控&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;使用df命令&lt;/li&gt;
&lt;li&gt;语法:&lt;code&gt;df[-h]&lt;/code&gt;： 查看磁盘使用率
&lt;ul&gt;
&lt;li&gt;-h:以更加人性化的单位显示&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;磁盘的信息监控还可以用&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;语法： &lt;code&gt;iostat [x][num1][num2]&lt;/code&gt;： 查看磁盘速率&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;-x: 显示更多信息&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;num1：数字，刷新间隔&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;num2:   数字，刷新几次&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;网络的状态监控&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#网络的状态监控&#34;&gt;#&lt;/a&gt; 网络的状态监控&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;语法： &lt;code&gt;sar -n DEV num1 num2&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;-n : 查看网络，DEV表示查看网络接口&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;num1：刷新间隔&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;num2:  查看次数&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;环境变量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#环境变量&#34;&gt;#&lt;/a&gt; 环境变量&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;定义:指的是操作系统在运行的时候，记录的一些关键性信息，用以辅助系统的运行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语法：&lt;code&gt;env&lt;/code&gt;:查看当前系统中记录的环境变量(键值对的形式)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;&amp;amp;&lt;/code&gt;&lt;/strong&gt;:取到环境变量，例:&lt;code&gt;echo $PWD&lt;/code&gt;（$引出键名，取出环境变量）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;export&lt;/code&gt;:自行设置临时变量&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;永久生效：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;针对当前用户生效,   配置在当前用户的&lt;code&gt;~/bashrc&lt;/code&gt;文件中&lt;/li&gt;
&lt;li&gt;针对所有用户生效，  配置在系统的&lt;code&gt;/etc/profie&lt;/code&gt;文件中&lt;/li&gt;
&lt;li&gt;并通过语法：&lt;code&gt;source 配置文件&lt;/code&gt;，进行立刻生效，或重新登陆Finalshell生效&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;上传和下载&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#上传和下载&#34;&gt;#&lt;/a&gt; 上传和下载&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;通过Finalshell拖拽&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;通过rz命令上传&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;通过sz命令下载&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;解压和压缩&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#解压和压缩&#34;&gt;#&lt;/a&gt; 解压和压缩&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;解压&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;tar命令，归档文件，没有太多文件体积的减少，仅仅是简单的封装&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语法：  &lt;code&gt;tar[-c -v -x -f -z -C]&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;-c:  创建压缩文件，用于压缩模式&lt;/li&gt;
&lt;li&gt;-v:  显示压缩、解压过程，显示进度&lt;/li&gt;
&lt;li&gt;-x:  解压模式&lt;/li&gt;
&lt;li&gt;-f:  要创建的文件，或要解压的文件，-f选项必须在所有选项中属于最后一个&lt;/li&gt;
&lt;li&gt;-z:  &lt;code&gt;gzip&lt;/code&gt;,模式，不使用-z就是普通的&lt;code&gt;tarball&lt;/code&gt;格式&lt;/li&gt;
&lt;li&gt;-C:  选择解压的目的地，用于解压模式&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;tar&lt;/strong&gt;常用的组合：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;-cvf&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;-zcvf&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;压缩&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;zip命令压缩文件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语法:  &lt;code&gt;zip[-r] 参数1，参数2，参数3....参数N&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;-r:压缩文件夹时使用&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;解压：&lt;code&gt;unzip [-d] 压缩包&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;实战环节&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实战环节&#34;&gt;#&lt;/a&gt; &lt;strong&gt;实战环节&lt;/strong&gt;&lt;/h3&gt;
&lt;h3 id=&#34;mysql57版本数据库管理系统安装系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mysql57版本数据库管理系统安装系统&#34;&gt;#&lt;/a&gt; mysql5.7版本数据库管理系统安装系统&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;配置yum 仓库：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;更新密钥&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;code&gt;rpm --import https://repo.mysql.com/RPM-GPG-KEY-mysql-2022&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;安装&lt;code&gt;Mysql yum&lt;/code&gt;库&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;code&gt;rpm -Uvh http://repo.mysql.com/mysql57-community-release-el7-7.noarch.rpm&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;安装MySQL&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;yum -y install mysql-community-server&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;完成MySQL的初始化配置：配置密码以及允许远程登陆的权限&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;Pipixia-001&lt;/code&gt;:mysql 密码，但是这个密码太复杂了&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果想设置简单密码，需要降低Mysql的密码安全级别&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;set global validate_password_policy=LOW; # 密码安全级别低&lt;br /&gt;
set global validate_password_length=4;   # 密码长度最低4位即可&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;然后就可以用简单密码了（课程中使用简单密码，为了方便，生产中不要这样）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;ALTER USER &#39;root&#39;@&#39;localhost&#39; IDENTIFIED BY &#39;123456&#39;；&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;所以现在mySQL的密码为&lt;code&gt;123456&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;配置MySQL的远程控制&lt;/strong&gt;(可选，但有风险)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;授权root远程登录&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;grant all privileges on *.* to root@&amp;quot;IP地址&amp;quot; identified by &#39;密码&#39; with grant option;&lt;/code&gt;IP地址即允许登陆的IP地址，也可以填写%，表示允许任何地址&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;密码表示给远程登录独立设置密码，和本地登陆的密码可以不同&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;刷新权限，生效&lt;code&gt;flush privileges;&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;退出MySQL的控制台界面：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;exit&lt;/code&gt;  或是&lt;code&gt;ctrl+d&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;检查端口&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;netstat -anp | grep 3306&lt;/code&gt;
&lt;ul&gt;
&lt;li&gt;3306:默认绑定3306端口&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;tomcat的安装和部署配置在tomcat用户中&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tomcat的安装和部署配置在tomcat用户中&#34;&gt;#&lt;/a&gt; Tomcat的安装和部署（配置在tomcat用户中）&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;实现了对Servlet和 JSP的支持，并提供作为Web服务器的特有功能&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;简单来讲，Tomcat是一个Web应用程序的托管平台，可以让用户编写的应用程序，被Tomcat所托管，提供网站服务（让用户开发的WEB应用程序，变成可被访问的网页）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;安装：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;安装JDK环境
&lt;ul&gt;
&lt;li&gt;遇到的问题：Oracle中下载安装包时需要注册账户，但是尝试了很多次一直报错403&lt;/li&gt;
&lt;li&gt;解决方法：在华为镜像网站中进行下载&lt;/li&gt;
&lt;li&gt;总结：之前就出现过这种情况，外网的总拒绝访问，需通过国内的镜像网站进行下载&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;解压并部署Tomcat(不要用root命令)
&lt;ul&gt;
&lt;li&gt;遇到问题：解压Tomcat的包的时候，忘记输入解压到的目标文件，导致后边创建软连接是显示五次文件&lt;/li&gt;
&lt;li&gt;解决方法：使用history命令找到问题所在，用mv 命令将目标文件转移到需要的文件下&lt;/li&gt;
&lt;li&gt;总结：tar解压运用不够熟练，需要多加练习&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;方式：在浏览器上搜：&lt;code&gt;192.168.254.132：8080&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;nginx的安装部署需要root权限&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#nginx的安装部署需要root权限&#34;&gt;#&lt;/a&gt; Nginx的安装部署(需要root权限)&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;作用：Nginx（engine x）是一个高性能的HTTP和反向代理web服务器，同时也提供了&lt;code&gt;IMAP/POP3/SMTP&lt;/code&gt;服务。和Tomcat一样，&lt;code&gt;Nginx&lt;/code&gt;可以托管用户编写的WEB应用程序成为可访问的网页服务，同时也可以作为流量代理服务器，控制流量的中转。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;方式：在浏览器中输入虚拟器端口：&lt;code&gt;192.168.254.132&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;rabbitmq的安装部署&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rabbitmq的安装部署&#34;&gt;#&lt;/a&gt; RabbitMQ的安装部署&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;RabbitMQ一款知名的开源消息队列系统，为企业提供消息的发布、订阅、点对点传输等消息服务。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;RabbitMQ的密码：&lt;code&gt;Pipixia-001&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;web网址：&lt;a href=&#34;http://192.168.254.130:15672&#34;&gt;http://192.168.254.130:15672&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;C:%5CUsers%5C18376%5CAppData%5CRoaming%5CTypora%5Ctypora-user-images%5Cimage-20260407213043730.png&#34; alt=&#34;image-20260407213043730&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;redis安装部署&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#redis安装部署&#34;&gt;#&lt;/a&gt; Redis安装部署&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;作用：redis是一个开源的、使用C语言编写的、支持网络交互的、可基于内存也可持久化的Key-Value数据库。redis的特点就是：快，可以基于内存存储数据并提供超低延迟、超快的检索速度&lt;br /&gt;
一般用于在系统中提供快速缓存的能力&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;elasticsearch安装部署&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#elasticsearch安装部署&#34;&gt;#&lt;/a&gt; ElasticSearch安装部署&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;作用：Elasticsearch（以下简称 es）是目前全文搜索引擎的首选。它可以快速地储存、搜索和分析海量数据。维基百科、Stack Overflow、Github 都采用它。Elasticsearch 简称 es，在企业内同样是一款应用非常广泛的搜索引擎服务。很多服务中的搜索功能，都是基于 es 来实现的&lt;/li&gt;
&lt;li&gt;yum install -y elasticsear&lt;/li&gt;
&lt;li&gt;web网址：&lt;a href=&#34;http://192.168.254.130:9200&#34;&gt;http://192.168.254.130:9200&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;集群化环境的前置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#集群化环境的前置&#34;&gt;#&lt;/a&gt; 集群化环境的前置&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;准备主机名映射&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用node1用户登录node2用户：&lt;code&gt;ssh root@node2&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;配置ssh免密登录&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;执行：&lt;code&gt;ssh-keygen -t rsa -b 4096&lt;/code&gt;：共用一个公钥&lt;/li&gt;
&lt;li&gt;各自分享登录密码&lt;/li&gt;
&lt;li&gt;直接输入&lt;code&gt;ssh+主机名&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;配置JDK环境：三台都分别配置&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;

 &lt;p&gt;Welcome to &lt;a href=&#34;https://hexo.io/&#34;&gt;Hexo&lt;/a&gt;! This is your very first post. Check &lt;a href=&#34;https://hexo.io/docs/&#34;&gt;documentation&lt;/a&gt; for more info. If you get any problems when using Hexo, you can find the answer in &lt;a href=&#34;https://hexo.io/docs/troubleshooting.html&#34;&gt;troubleshooting&lt;/a&gt; or you can ask me on &lt;a href=&#34;https://github.com/hexojs/hexo/issues&#34;&gt;GitHub&lt;/a&gt;.&lt;/p&gt;
&lt;h2 id=&#34;quick-start&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#quick-start&#34;&gt;#&lt;/a&gt; Quick Start&lt;/h2&gt;
&lt;h3 id=&#34;create-a-new-post&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#create-a-new-post&#34;&gt;#&lt;/a&gt; Create a new post&lt;/h3&gt;
&lt;p&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ hexo new &lt;span class=&#34;string&#34;&gt;&amp;quot;My New Post&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;More info: &lt;a href=&#34;https://hexo.io/docs/writing.html&#34;&gt;Writing&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;run-server&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#run-server&#34;&gt;#&lt;/a&gt; Run server&lt;/h3&gt;
&lt;p&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ hexo server&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;More info: &lt;a href=&#34;https://hexo.io/docs/server.html&#34;&gt;Server&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;generate-static-files&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#generate-static-files&#34;&gt;#&lt;/a&gt; Generate static files&lt;/h3&gt;
&lt;p&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ hexo generate&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;More info: &lt;a href=&#34;https://hexo.io/docs/generating.html&#34;&gt;Generating&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;deploy-to-remote-sites&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#deploy-to-remote-sites&#34;&gt;#&lt;/a&gt; Deploy to remote sites&lt;/h3&gt;
&lt;p&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ hexo deploy&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;More info: &lt;a href=&#34;https://hexo.io/docs/one-command-deployment.html&#34;&gt;Deployment&lt;/a&gt;&lt;/p&gt;
